SELECT
    q.id_registration_audit,
    q.match_status,
    q.id_membership_periods_sa,
    q.purchased_on_mp,
    q.purchased_on_adjusted_mp,
    ROW_NUMBER() OVER (
        PARTITION BY q.match_status
        ORDER BY q.id_registration_audit
    ) AS status_row_num,
    COUNT(*) OVER (
        PARTITION BY q.match_status
    ) AS status_total,
    CONCAT(
        ROW_NUMBER() OVER (
            PARTITION BY q.match_status
            ORDER BY q.id_registration_audit
        ),
        ' of ',
        COUNT(*) OVER (
            PARTITION BY q.match_status
        ),
        ' ',
        q.match_status
    ) AS status_position
FROM (
SELECT
    t.id_registration_audit,
    CASE
        WHEN s.id_registration_audit IS NULL THEN 'NOT FOUND'
        ELSE 'FOUND'
    END AS match_status,
    s.id_membership_periods_sa,
    s.purchased_on_mp,
    s.purchased_on_adjusted_mp
